import { Component, inject, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, FormGroup, Validators, ReactiveFormsModule } from '@angular/forms';
import { SupplierService } from '../../../services/supplier.service';
import { Supplier } from '../../../models';
import { LucideAngularModule } from 'lucide-angular';

@Component({
  selector: 'app-supplier-manager',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, LucideAngularModule],
  templateUrl: './supplier-manager.html',
  styleUrls: ['./supplier-manager.css']
})
export class SupplierManager implements OnInit {
  private supplierService = inject(SupplierService);
  private fb = inject(FormBuilder);

  suppliers: Supplier[] = [];
  showSupplierForm = false;
  isEditing = false;
  currentSupplierId: string | null = null;
  
  supplierForm: FormGroup;
  isLoading = true;

  constructor() {
    this.supplierForm = this.fb.group({
      company_name: ['', [Validators.required, Validators.minLength(2)]],
      contact_name: [''],
      email: ['', [Validators.email]],
      phone: [''],
      address: [''],
    });
  }

  async ngOnInit() {
    await this.loadSuppliers();
  }

  async loadSuppliers() {
    this.isLoading = true;
    try {
      await this.supplierService.loadSuppliers();
      this.supplierService.suppliers$.subscribe(suppliers => {
        this.suppliers = suppliers;
        this.isLoading = false;
      });
    } catch (error) {
      console.error('Error loading suppliers:', error);
      this.isLoading = false;
    }
  }

  async onSubmit() {
    if (this.supplierForm.invalid) {
      this.markFormGroupTouched();
      return;
    }

    try {
      if (this.isEditing && this.currentSupplierId) {
        const success = await this.updateSupplier(this.currentSupplierId, this.supplierForm.value);
        if (success) {
          console.log('Fornitore aggiornato con successo');
          this.resetForm();
        }
      } else {
        const supplier = await this.supplierService.createSupplier(this.supplierForm.value);
        if (supplier) {
          console.log('Fornitore creato con successo');
          this.resetForm();
        }
      }
    } catch (error) {
      console.error('Errore durante il salvataggio:', error);
    }
  }

  async updateSupplier(id: string, updates: Partial<Supplier>): Promise<boolean> {
    // Implementa l'update nel servizio se non esiste
    try {
      const { data, error } = await this.supplierService['supabaseService'].getSupabaseClient()
        .from('suppliers')
        .update(updates)
        .eq('id', id)
        .select()
        .single();

      if (error) throw error;
      await this.loadSuppliers();
      return true;
    } catch (error) {
      console.error('Error updating supplier:', error);
      return false;
    }
  }

  async deleteSupplier(id: string) {
    if (confirm('Sei sicuro di voler eliminare questo fornitore?')) {
      try {
        const { error } = await this.supplierService['supabaseService'].getSupabaseClient()
          .from('suppliers')
          .delete()
          .eq('id', id);

        if (error) throw error;
        await this.loadSuppliers();
        console.log('Fornitore eliminato');
      } catch (error) {
        console.error('Error deleting supplier:', error);
      }
    }
  }

  editSupplier(supplier: Supplier) {
    this.isEditing = true;
    this.currentSupplierId = supplier.id;
    this.supplierForm.patchValue({
      company_name: supplier.company_name,
      contact_name: supplier.contact_name || '',
      email: supplier.email || '',
      phone: supplier.phone || '',
      address: supplier.address || ''
    });
    this.showSupplierForm = true;
  }

  newSupplier() {
    this.resetForm();
    this.showSupplierForm = true;
    this.isEditing = false;
  }

  resetForm() {
    this.supplierForm.reset({
      company_name: '',
      contact_name: '',
      email: '',
      phone: '',
      address: ''
    });
    this.isEditing = false;
    this.currentSupplierId = null;
    this.showSupplierForm = false;
  }

  private markFormGroupTouched() {
    Object.keys(this.supplierForm.controls).forEach(key => {
      const control = this.supplierForm.get(key);
      control?.markAsTouched();
    });
  }

  // Getters per il template
  get company_name() { return this.supplierForm.get('company_name'); }
  get email() { return this.supplierForm.get('email'); }
}